// // This counter decrements from 15 to 0 and wraps around to 15 upon reset.
module sync_counter(
    input wire clk,
    input wire rst,
    output reg [3:0] count
);

    always @(posedge clk) begin
        if (rst)
            count <= 4'b0000;
        else
            count <= count + 1;
    end

endmodule
